import os
import shutil
from zipfile import ZipFile
import tarfile

def backup_directory(source_dir, archive_name, format):
    if format == 'tar.gz':
        with tarfile.open(archive_name + '.tar.gz', 'w:gz') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif format == 'tar.bz2':
        with tarfile.open(archive_name + '.tar.bz2', 'w:bz2') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif format == 'zip':
        with ZipFile(archive_name + '.zip', 'w') as zipf:
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    zipf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), start=source_dir))
    elif format == '7z':
        try:
            import py7zr
            with py7zr.SevenZipFile(archive_name + '.7z', mode='w') as szf:
                for root, dirs, files in os.walk(source_dir):
                    for file in files:
                        szf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), start=source_dir))
        except ImportError:
            print("py7zr is not installed. Please install py7zr to use 7z format.")
    else:
        print(f"Unsupported format: {format}")

